//! Differential tests against the TypeScript oracle (@zkpassport/utils +
//! @zkpassport/poseidon2). Vectors are generated by rust/scripts/gen-vectors.ts:
//!
//!   bun rust/scripts/gen-vectors.ts
//!
//! Every ported function must produce output identical to the TS implementation.

use num_bigint::BigUint;
use serde_json::json;
use serde::Deserialize;
use zkpassport_core::{
    barrett, bytes, commitments, disclosure, dsc, id_data, input_gen, integrity, poseidon2,
    registry, select, signature, sod,
};

/// Minimal base64 decode (standard alphabet, padded) to avoid a dev-dependency.
fn base64_decode(s: &str) -> Vec<u8> {
    const ALPHABET: &[u8] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
    let mut lookup = [255u8; 256];
    for (i, &c) in ALPHABET.iter().enumerate() {
        lookup[c as usize] = i as u8;
    }
    let mut out = Vec::new();
    let mut buf: u32 = 0;
    let mut bits = 0;
    for &c in s.as_bytes() {
        if c == b'=' || c == b'\n' || c == b'\r' {
            continue;
        }
        let v = lookup[c as usize];
        assert_ne!(v, 255, "invalid base64 char");
        buf = (buf << 6) | v as u32;
        bits += 6;
        if bits >= 8 {
            bits -= 8;
            out.push((buf >> bits) as u8);
        }
    }
    out
}

