impl SaltsJson {
    fn to_salts(&self) -> commitments::IntegrityToDisclosureSalts {
        commitments::IntegrityToDisclosureSalts {
            dg1_salt: dec_or_hex(&self.dg1_salt),
            expiry_date_salt: dec_or_hex(&self.expiry_date_salt),
            dg2_hash_salt: dec_or_hex(&self.dg2_hash_salt),
            private_nullifier_salt: dec_or_hex(&self.private_nullifier_salt),
        }
    }
}

