fn load() -> Vectors {
    let path = concat!(env!("CARGO_MANIFEST_DIR"), "/../../vectors/vectors.json");
    let data = std::fs::read_to_string(path)
        .expect("vectors.json missing — run `bun rust/scripts/gen-vectors.ts` first");
    serde_json::from_str(&data).expect("vectors.json parse")
}

fn dec(s: &str) -> BigUint {
    s.parse().expect("decimal bigint")
}

fn dec_or_hex(s: &str) -> BigUint {
    if let Some(hex) = s.strip_prefix("0x") {
        BigUint::parse_bytes(hex.as_bytes(), 16).expect("hex bigint")
    } else {
        dec(s)
    }
}

