#[test]
fn commitment_primitives_match_ts() {
    let c = load().commitments;

    let sb = &c.salted_bytes;
    assert_eq!(
        commitments::salted_value_hash_bytes(&dec_or_hex(&sb.salt), &sb.bytes),
        dec(&sb.result),
        "salted_bytes"
    );

    let ss = &c.salted_scalar;
    assert_eq!(
        commitments::salted_value_hash_scalar(&dec_or_hex(&ss.salt), &dec(&ss.value)),
        dec(&ss.result),
        "salted_scalar"
    );

    let pn = &c.private_nullifier;
    assert_eq!(
        commitments::calculate_private_nullifier(&pn.dg1, &pn.e_content, &pn.sod_sig),
        dec(&pn.result),
        "private_nullifier"
    );

    let st = &c.salt_country_tbs;
    assert_eq!(
        commitments::hash_salt_country_tbs(&dec_or_hex(&st.salt), &st.country, &st.tbs_padded),
        dec(&st.result),
        "salt_country_tbs"
    );

    let ci = &c.comm_in;
    assert_eq!(
        commitments::hash_salt_country_signed_attr_dg1_e_content_private_nullifier(
            &dec_or_hex(&ci.salt),
            &ci.country,
            &ci.padded_signed_attr,
            &BigUint::from(ci.signed_attr_size),
            &ci.dg1,
            &ci.e_content,
            &dec(&ci.private_nullifier),
        ),
        dec(&ci.result),
        "comm_in"
    );

    let pl = &c.pack_le_hash;
    assert_eq!(
        commitments::pack_le_bytes_and_hash_poseidon2(&pl.bytes),
        dec(&pl.result),
        "pack_le_hash"
    );

    let sd = &c.salt_dg1_dg2;
    assert_eq!(
        commitments::hash_salt_dg1_dg2_hash_private_nullifier(
            &sd.salts.to_salts(),
            &sd.dg1,
            &sd.expiry_date,
            &dec(&sd.dg2_hash_normalized),
            sd.dg2_hash_type,
            &dec(&sd.private_nullifier),
        ),
        dec(&sd.result),
        "salt_dg1_dg2"
    );
}

