#[test]
fn id_data_circuit_inputs_match_ts() {
    for case in load().id_data.iter() {
        let dsc_pubkey = if let Some(rsa) = &case.rsa {
            id_data::DscPublicKey::Rsa {
                modulus: dec(&rsa.modulus).to_bytes_be(),
                exponent: rsa.exponent,
            }
        } else {
            let ec = case.ecdsa.as_ref().expect("rsa or ecdsa key");
            id_data::DscPublicKey::Ecdsa {
                public_key: ec.public_key.clone(),
                curve_n: dec(&ec.n),
                curve_byte_size: ec.byte_size,
            }
        };
        let input = id_data::IdDataInput {
            dg1: &case.dg1,
            e_content: &case.e_content,
            signed_attributes: &case.signed_attributes,
            sod_signature: &case.sod_signature,
            tbs_certificate: &case.tbs_certificate,
            dsc_country: &case.dsc_country,
            dsc_pubkey,
            pss_salt_len: case.pss_salt_len,
        };
        let got = id_data::get_id_data_circuit_inputs(
            &input,
            &dec(&case.salt_in),
            &dec(&case.salt_out),
        );
        assert_eq!(got, case.expected, "id_data fixture '{}'", case.name);
    }
}

