#[test]
fn sod_parsing_matches_ts() {
    for case in load().sod.iter() {
        let der = base64_decode(&case.sod_base64);
        let parsed = sod::parse_sod(&der).expect("parse SOD");
        let exp = &case.expected;
        let n = &case.name;
        assert_eq!(parsed.e_content, exp.e_content, "{n}: e_content");
        assert_eq!(
            parsed.signed_attributes, exp.signed_attributes,
            "{n}: signed_attributes"
        );
        assert_eq!(
            parsed.signer_signature, exp.signer_signature,
            "{n}: signer_signature"
        );
        assert_eq!(parsed.signer_sig_alg, exp.signer_sig_alg, "{n}: signer_sig_alg");
        assert_eq!(
            parsed.signer_sig_alg_params, exp.signer_sig_alg_params,
            "{n}: signer_sig_alg_params"
        );
        assert_eq!(
            parsed.signer_digest_alg, exp.signer_digest_alg,
            "{n}: signer_digest_alg"
        );
        assert_eq!(parsed.dg_hash_alg, exp.dg_hash_alg, "{n}: dg_hash_alg");
        assert_eq!(parsed.dg_hashes, exp.dg_hashes, "{n}: dg_hashes");
        assert_eq!(
            parsed.tbs_certificate, exp.tbs_certificate,
            "{n}: tbs_certificate"
        );
        assert_eq!(parsed.cert_sig_alg, exp.cert_sig_alg, "{n}: cert_sig_alg");
        assert_eq!(parsed.cert_signature, exp.cert_signature, "{n}: cert_signature");
        assert_eq!(parsed.dsc_country, exp.dsc_country, "{n}: dsc_country");
        assert_eq!(parsed.signature_type(), exp.signature_type, "{n}: signature_type");
        match &parsed.public_key {
            sod::SodPublicKey::Rsa { modulus, exponent } => {
                assert_eq!(exp.public_key["type"], "rsa", "{n}: pk type");
                assert_eq!(
                    BigUint::from_bytes_be(modulus),
                    dec(exp.public_key["modulus"].as_str().unwrap()),
                    "{n}: modulus"
                );
                assert_eq!(
                    *exponent,
                    exp.public_key["exponent"].as_u64().unwrap(),
                    "{n}: exponent"
                );
            }
            sod::SodPublicKey::Ecdsa { public_key, curve } => {
                assert_eq!(exp.public_key["type"], "ecdsa", "{n}: pk type");
                let exp_pk: Vec<u8> = exp.public_key["public_key"]
                    .as_array()
                    .unwrap()
                    .iter()
                    .map(|v| v.as_u64().unwrap() as u8)
                    .collect();
                assert_eq!(*public_key, exp_pk, "{n}: ec public key");
                assert_eq!(curve, exp.public_key["curve"].as_str().unwrap(), "{n}: curve");
            }
        }
    }
}

#[test]
fn csca_matching_matches_ts() {
    // getCscaForPassportAsync's primary AKI/SKI path must select the same
    // CSCA the TS pipeline selected (compared by fingerprint).
    let fixtures = concat!(
        env!("CARGO_MANIFEST_DIR"),
        "/../../../packages/zkpassport-utils/tests/fixtures/root-certs-v1.json"
    );
    let file: serde_json::Value =
        serde_json::from_str(&std::fs::read_to_string(fixtures).expect("root-certs-v1.json"))
            .unwrap();
    let certs: Vec<registry::PackagedCertificate> =
        serde_json::from_value(file["certificates"].clone()).unwrap();
    let v = load();
    for sod_case in v.sod.iter() {
        let der = base64_decode(&sod_case.sod_base64);
        let parsed = sod::parse_sod(&der).expect("parse SOD");
        let matched = registry::match_csca(
            &certs,
            &parsed.dsc_country,
            parsed.authority_key_identifier.as_deref(),
        )
        .unwrap_or_else(|| panic!("{}: no CSCA matched", sod_case.name));
        let expected = v
            .dsc
            .iter()
            .find(|c| c.name == sod_case.name)
            .unwrap()
            .csca
            .fingerprint
            .clone();
        assert_eq!(matched.fingerprint, expected, "{}: csca", sod_case.name);
    }
}

#[test]
fn circuit_names_match_app_logic() {
    let v = load();
    for case in v.circuit_names.iter() {
        let sod_case = v.sod.iter().find(|s| s.name == case.name).unwrap();
        let dsc_case = v.dsc.iter().find(|c| c.name == case.name).unwrap();
        let der = base64_decode(&sod_case.sod_base64);
        let parsed = sod::parse_sod(&der).expect("parse SOD");
        let names =
            select::get_circuit_names(&parsed, &dsc_case.csca, false).expect("circuit names");
        assert_eq!(names.dsc, case.expected["dsc"].as_str().unwrap(), "{}: dsc", case.name);
        assert_eq!(
            names.id_data,
            case.expected["id_data"].as_str().unwrap(),
            "{}: id_data",
            case.name
        );
        assert_eq!(
            names.integrity,
            case.expected["integrity"].as_str().unwrap(),
            "{}: integrity",
            case.name
        );
        assert_eq!(names.age, case.expected["age"].as_str().unwrap(), "{}: age", case.name);
    }
}

#[test]
fn disclosure_builders_match_ts() {
    let v = load();
    for case in v.disclosures.iter() {
        let name = case.label.split(':').next().unwrap();
        // Reuse the passport raw fields from the matching age vector.
        let age = v.age.iter().find(|a| a.name == format!("{name}:gte18")).unwrap();
        let dg1 = &age.dg1;
        let mrz = zkpassport_core::input_gen::mrz_from_dg1(dg1).expect("mrz");
        let input = disclosure::DisclosureInput {
            dg1,
            e_content: &age.e_content,
            sod_signature_processed: &age.sod_signature_processed,
            dg2_hash: &age.dg2_hash,
            expiry_date: &age.expiry_date,
            mrz: &mrz,
        };
        let salts = input_gen::InputGenSalts::from_master(dec(&case.master_salt)).disclosure;
        let z = &BigUint::from(0u8);
        let got = match case.kind.as_str() {
            "disclose" => {
                let f = disclosure::DiscloseFields {
                    firstname: *case.fields.get("firstname").unwrap_or(&false),
                    document_type: *case.fields.get("document_type").unwrap_or(&false),
                    ..Default::default()
                };
                disclosure::get_disclose_circuit_inputs(&input, &f, &salts, z, z, z, 1789000000, None)
            }
            "birthdate" | "expiry" => {
                let bounds = disclosure::DateBounds {
                    min: if case.min != 0 { Some(case.min) } else { None },
                    max: if case.max != 0 { Some(case.max) } else { None },
                };
                disclosure::get_date_circuit_inputs(
                    &input, &bounds, case.kind == "birthdate", &salts, z, z, z, 1789000000, None,
                )
            }
            "nat_in" => disclosure::get_country_inclusion_circuit_inputs(
                &input, &case.countries, &salts, z, z, z, 1789000000, None,
            ),
            "issue_out" => disclosure::get_country_exclusion_circuit_inputs(
                &input, &case.countries, &salts, z, z, z, 1789000000, None,
            ),
            "bind" => {
                let bound = disclosure::BoundData {
                    user_address: Some(case.user_address.clone()),
                    custom_data: Some(case.custom_data.clone()),
                    chain_id: None,
                };
                disclosure::get_bind_circuit_inputs(&input, &bound, &salts, z, z, z, 1789000000, None)
            }
            other => panic!("unknown disclosure kind {other}"),
        }
        .unwrap_or_else(|e| panic!("{}: {e}", case.label));
        assert_eq!(got, case.expected, "disclosure {}", case.label);
    }
}

#[test]
fn outer_assembly_matches_ts() {
    use zkpassport_core::outer;
    let v = load();

    for c in v.num_pub.iter() {
        assert_eq!(outer::num_public_inputs(&c.name), c.count, "numPub {}", c.name);
    }

    // ultraVkToFields
    assert_eq!(
        outer::ultra_vk_to_fields(&v.ultra_vk.bytes),
        v.ultra_vk.result,
        "ultraVkToFields"
    );

    // getProofData
    let pd = outer::get_proof_data(&v.proof_data2.proof, v.proof_data2.num).unwrap();
    assert_eq!(json!(pd.proof), v.proof_data2.result["proof"], "proofData.proof");
    assert_eq!(json!(pd.public_inputs), v.proof_data2.result["publicInputs"], "proofData.publicInputs");

    // circuit merkle proof (against the manifest fixture)
    let manifest_path = concat!(
        env!("CARGO_MANIFEST_DIR"),
        "/../../../packages/zkpassport-utils/tests/fixtures/manifest.json"
    );
    let manifest: zkpassport_core::plan::CircuitManifest =
        serde_json::from_str(&std::fs::read_to_string(manifest_path).unwrap()).unwrap();
    let cm = &v.circuit_merkle;
    assert_eq!(outer::circuit_leaves(&manifest).len(), cm.leaf_count, "leaf count");
    let (index, path) = outer::circuit_merkle_proof(&manifest, &cm.key_hash).unwrap();
    assert_eq!(index, format!("0x{:x}", cm.index), "circuit tree index");
    assert_eq!(path, cm.path, "circuit tree path");

    // getOuterCircuitInputs — synthetic subproofs
    let ocp = |tag: &str, pis: &[&str]| outer::OuterSubproof {
        proof: vec![format!("0x{tag}1")],
        public_inputs: pis.iter().map(|s| s.to_string()).collect(),
        vkey: vec![format!("0x{tag}2")],
        key_hash: format!("0x{tag}3"),
        tree_hash_path: vec![format!("0x{tag}4"), format!("0x{tag}5")],
        tree_index: format!("0x{tag}6"),
    };
    let csc = ocp("a", &["0xa0", "0xa1", "0xa2"]);
    let dsc_id = ocp("b", &["0xb0", "0xb1"]);
    let integ = ocp("c", &["0xc0", "0xc1"]);
    let disc1 = ocp("d", &["0xd0", "0x64", "0xd2", "0xd3", "0xd4", "0xd5", "0x99", "0xd7"]);
    let disc2 = ocp("e", &["0xe0", "0x64", "0xe2", "0xe3", "0xe4", "0xe5", "0x0", "0xe7"]);
    let got = outer::get_outer_circuit_inputs(
        &csc, &dsc_id, &integ, &[disc1, disc2], &v.outer_inputs.circuit_root,
    )
    .unwrap();
    assert_eq!(got, v.outer_inputs.result, "getOuterCircuitInputs");
}

