/// The full pipeline: raw SOD DER + DG1 + DG2 hash → all four circuit input
/// sets, each compared against the TS builder outputs captured above.
#[test]
fn end_to_end_input_generation_matches_ts() {
    let v = load();
    let leaves: Vec<BigUint> = v.dsc_meta.cert_leaves.iter().map(|s| dec(s)).collect();
    let meta = dsc::PackagedCertsMeta {
        version: v.dsc_meta.version,
        root: &v.dsc_meta.root,
        timestamp: v.dsc_meta.timestamp,
        revocations: &v.dsc_meta.revocations,
        masterlists: &v.dsc_meta.masterlists,
    };
    for sod_case in v.sod.iter() {
        let name = &sod_case.name;
        let age_case = v
            .age
            .iter()
            .find(|a| a.name == format!("{name}:gte18"))
            .expect("age case");
        let id_case = v.id_data.iter().find(|c| &c.name == name).expect("id case");
        let integ_case = v.integrity.iter().find(|c| &c.name == name).expect("integrity case");
        let dsc_case = v.dsc.iter().find(|c| &c.name == name).expect("dsc case");

        let der = base64_decode(&sod_case.sod_base64);
        let query = serde_json::json!({ "age": { "gte": 18 } });
        let params = input_gen::GenerateParams {
            sod_der: &der,
            dg1: &id_case.dg1,
            dg2_hash: &age_case.dg2_hash,
            csca: &dsc_case.csca,
            certs_meta: &meta,
            cert_leaves: &leaves,
            query: &query,
            evm: false,
            nullifier_secret: BigUint::from(0u8),
            service_scope: dec(&age_case.service_scope),
            service_subscope: dec(&age_case.service_subscope),
            current_date_timestamp: age_case.current_date,
        };
        let salts = input_gen::InputGenSalts {
            dsc_salt: dec(&dsc_case.salt),
            id_salt_in: dec(&id_case.salt_in),
            id_salt_out: dec(&id_case.salt_out),
            integrity_salt_in: dec(&integ_case.salt_in),
            disclosure: age_case.salts.to_salts(),
        };
        let out = input_gen::generate_all_inputs(&params, &salts).expect("generate inputs");
        assert_eq!(out["dsc"], dsc_case.expected, "{name}: dsc");
        assert_eq!(out["id_data"], id_case.expected, "{name}: id_data");
        assert_eq!(out["integrity"], integ_case.expected, "{name}: integrity");
        // Query-driven: age is now the single produced disclosure.
        let disc = &out["disclosures"].as_array().unwrap()[0];
        assert_eq!(disc["name"], "compare_age");
        assert_eq!(disc["inputs"], age_case.expected, "{name}: age");
    }
}

